def test_structure_fan_out_small_graph():
    G = nx.DiGraph()
    hub = "h"
    for i in range(4):
        G.add_edge(hub, f"d{i}", amount=1.0)
    assert structure_typology(G) == FAN_OUT

def test_structure_peel_path():
    G = nx.DiGraph()
    for i in range(4):
        G.add_edge(f"a{i}", f"a{i + 1}", amount=1.0)
    assert structure_typology(G) == PEEL
